19	const PROCESSING_FEE = 5;
20	
21	const COMPONENT_TYPES = ["rune", "moonstone"];
22	const BLOCK_SIZE = 3;
23	const BLOCK_PREMIUM = 60;
24	
25	function countByType(items: Item[]): Record<string, number> {
26	  const counts: Record<string, number> = {};
27	  for (const item of items) {
28	    counts[item.type] = (counts[item.type] ?? 0) + 1;
29	  }
30	  return counts;
31	}
32	
33	function premiumForGroup(type: string, count: number): number {
34	  if (COMPONENT_TYPES.includes(type) && count === BLOCK_SIZE) {
35	    return BLOCK_PREMIUM;
36	  }
37	  return count * (BASE_PREMIUM[type] ?? 0);
38	}
39	
40	export function quote(items: Item[], customer: CustomerContext): number {
41	  const counts = countByType(items);
42	
43	  let premium = 0;
44	  for (const [type, count] of Object.entries(counts)) {
45	    premium += premiumForGroup(type, count);
46	  }
47	
48	  return premium + PROCESSING_FEE;
49	}
